// init
router.use(function (req, next) {
  console.log(req);
  router.req = req;
  authStore.resolveSession().then(() => {
    if (isLoggedAndDataReady || !authStore.isLogged()) {
      next();
      return;
    }

    __.ui.showSpinner();

    appStore.bootstrap(true);

    isLoggedAndDataReady = true;

    // not launch in later because it doesn't need to be finished
    // before rendering the route
    // notificationStore.fetchAllInit();
    ticketStore.fetchAllInit();
    alerteStore.fetchAllInit();

    return authStore
      .fetchCurrent()
      .then(() => {
        authStore.changeCssFile();

        return (
          authStore
            .fetchModules()
            // eslint-disable-next-line max-nested-callbacks
            .then(() => {
              return Promise.all([
                buildingStore.fetchAll(),
                buildingStore.fetchFriends(),
                dataTypeStore.fetchAll(),
                usageStore.fetchAll(),
                actuatorStore.fetchModels(),
                sensorStore.fetchAll(),
              ]);
            })
            // eslint-disable-next-line max-nested-callbacks
            .then(() => {
              // TODO: uncomment when back is updated
              // meterStore.fetchAllInit();
              objectiveStore.fetchAll();
              entityStore.fetchAllAffiliations();
              __.ui.hideSpinner();
              return next();
            })
            // eslint-disable-next-line max-nested-callbacks
            .then(() => {
              appStore.bootstrap(false);
            })
            // eslint-disable-next-line max-nested-callbacks
            .catch((err) => next(err))
        );
      })
      .catch((err) => {
        next(err);
      });
  });
});

export const MODULES_ROUTES = {
  impact: 'impact',
  scheduler: 'scheduler',
  visualization: 'visualization',
  contest: 'contests',
  greenpoints: 'greenpoints',
  advice: 'advices',
  'apolis-planeta': 'apolis-planeta',
  helpDesk: 'helpdesk',
  dashboard: 'dashboard',
  arrayConso: 'consos',
  generalFollowUp: 'generalFollowUp',
  reporting: 'reporting',
  sensorsState: 'sensorsState',
  plan: 'plan',
  robinson: 'robinson',
  challenge: 'challenge',
  chooseProject: 'choose-project',
  drive: 'drive',
  terdecree: 'terdecree',
};

// shortcut, redirect to dashboard or login
// eslint-disable-next-line complexity
router.use('home', '/(\\?.*)', function () {
  if (!authStore.isLogged()) {
    return router.replaceWith('login');
  }

  const user = authStore.getState();

  if (user.modules.length) {
    const modulesLn = user.modules.length;
    for (let i = 0; i < modulesLn; i++) {
      const module = user.modules[i];
      if (Object.prototype.hasOwnProperty.call(MODULES_ROUTES, module)) {
        return router.replaceWith(MODULES_ROUTES[module]);
      }
    }
  }
  renderWithApp(<ErrorOccured message='no module found' />);
});
